import { describe, expect, it } from '@a0n/gnosis/test';
import { encode, decode, type GgProgram } from '../packed-knot-encoder';

describe('binary-props', () => {
  it('preserves TypedArray properties across encode and decode', () => {
    const originalTensor = new Float32Array([1.1, 2.2, 3.3, 4.4]);
    const originalBlob = new Uint8Array([10, 20, 30, 40]);
    
    const program: GgProgram = {
      nodes: [
        {
          id: 'node-A',
          labels: ['Test'],
          properties: {
            tensorVal: originalTensor,
            blobVal: originalBlob,
            strVal: 'hello',
          },
        },
      ],
      edges: [],
    };

    const encoded = encode(program);
    const decoded = decode(encoded);

    const nodeA = decoded.nodes.find(n => n.id === 'node-A');
    expect(nodeA).toBeDefined();

    // Verify Float32Array parsing
    const tensorProp = nodeA!.properties['tensorVal'];
    expect(tensorProp).toBeInstanceOf(Float32Array);
    const castedTensor = tensorProp as Float32Array;
    expect(castedTensor.length).toBe(4);
    // Floating point comparison
    expect(Math.abs(castedTensor[0] - 1.1)).toBeLessThan(0.001);

    // Verify Uint8Array parsing
    const blobProp = nodeA!.properties['blobVal'];
    expect(blobProp).toBeInstanceOf(Uint8Array);
    const castedBlob = blobProp as Uint8Array;
    expect(castedBlob.length).toBe(4);
    expect(castedBlob[0]).toBe(10);

    // Verify regular properties
    expect(nodeA!.properties['strVal']).toBe('hello');
  });

  it('preserves edge properties', () => {
    const program: GgProgram = {
      nodes: [
        { id: 'n1', labels: [], properties: {} },
        { id: 'n2', labels: [], properties: {} },
      ],
      edges: [
        {
          sourceIds: ['n1'],
          targetIds: ['n2'],
          type: 'PROCESS',
          properties: {
            weights: new Float32Array([0.5, 0.5]),
          },
        },
      ],
    };

    const encoded = encode(program);
    const decoded = decode(encoded);

    const edge = decoded.edges[0];
    expect(edge).toBeDefined();

    const weights = edge.properties['weights'];
    expect(weights).toBeInstanceOf(Float32Array);
    expect((weights as Float32Array)[0]).toBe(0.5);
  });
});
